INSERT INTO `ai_conversation_history` VALUES (1,1,'default','你好啊','👋 嗨～你好呀！我是小智，你的校园生活小助手🤗！无论是查课表、看成绩，还是找失物招领，都可以随时问我哦～✨ 你今天想先了解哪方面的校园服务呀？',NULL,NULL,NULL,NULL,'2026-07-17 10:46:41'),(2,1,'default','我想查 成绩','🎉 查成绩超简单哒！跟着小智的步骤来：  \n1️⃣ 登录平台后，在首页找到 **「我的成绩查询」** 模块（一般在学生功能区前几个位置哦~）  \n2️⃣ 点击进去后，可以按学期筛选成绩，补考/重修的课程会有特殊标识✨  \n3️⃣ 需要打印的话，记得先截图保存呀~  \n\n如果找不到入口，随时喊小智帮你定位📍！还有其他问题也尽管问呀~ 😊',NULL,NULL,NULL,NULL,'2026-07-17 10:46:58'),(3,1,'default','hi','嗨！你好呀～我是小智，你的校园服务智能向导😊 有什么需要帮忙的吗？比如查成绩、看课表、办业务，或者想了解学校公告，都可以问我哦！',NULL,NULL,NULL,NULL,'2026-07-17 12:35:30'),(4,1,'float','你好你好','哈喽同学！👋 我是小智，你的校园智能小助手～有什么需要帮忙的吗？无论是查课表、找功能，还是咨询校园事务，我都能帮你快速搞定！😊',NULL,NULL,NULL,NULL,'2026-07-17 16:11:25'),(5,18,'float','你好','你好呀！👋 我是小智，你的校园服务智能向导！有什么需要帮忙的吗？无论是查成绩、看课表，还是找某个功能入口，都可以问我哦~😊',NULL,NULL,NULL,NULL,'2026-07-18 11:05:00'),(6,2,'float','nihao','你好呀！😊 我是小智，你的校园服务智能助手！有什么需要帮忙的吗？无论是查课表、看成绩，还是了解学校通知，我都能帮你找到对应的功能入口哦～',NULL,NULL,NULL,NULL,'2026-07-18 11:47:30'),(7,2,'float','我想选课','同学你好呀！😊 选课功能在平台里很方便哦！如果你是**学生**，可以按照以下步骤操作：\n\n1️⃣ 登录智慧校园服务平台，进入**学生角色**界面  \n2️⃣ 点击左侧菜单中的 **「课程情况总览」** 或 **「我的课表」**  \n3️⃣ 在课程情况总览里，你可以看到自己已选的课程、已修学分等信息  \n4️⃣ 如果需要**手动选课**，可以联系**管理员**（在管理员功能中“学生选课管理”模块帮你操作）\n\n小提示：选课前记得先看看**系统公告**和**学校新闻**，了解选课时间安排和注意事项哦～如果遇到选课问题，也可以直接找学院教务老师帮忙！📚✨',NULL,NULL,NULL,NULL,'2026-07-18 11:47:38'),(8,2,'float','选课在哪','选课名单在这里：<a href=\"/teacher/enrollment\" target=\"_blank\">/teacher/enrollment</a>',NULL,NULL,NULL,NULL,'2026-07-18 11:53:36'),(9,1,'float','我想选课','选课功能在 **学习中心** 里哦～你可以直接点击这里进入：  \n📚 <a href=\"/student/study\" target=\"_blank\">/student/study</a>',NULL,NULL,NULL,NULL,'2026-07-18 11:54:00'),(10,1,'float','我今天吃啥对身体好','哈哈，我虽然是智慧校园助手，但暂时还没法帮你点外卖或推荐菜谱哦！不过，如果你想了解学校食堂的营业信息或校园健康饮食建议，可以试试查看 **校园服务** 里的相关咨询：  \n<a href=\"/student/applications\" target=\"_blank\">🏠 校园服务（奖学金/竞赛/咨询/实践）</a>  \n\n或者，如果你想查查今天的课表安排，顺便去食堂吃饭，可以戳这里：  \n<a href=\"/student/study\" target=\"_blank\">📚 学习中心（课表/成绩/评教/选课）</a>  \n\n记得多吃蔬菜水果，少熬夜，身体棒棒哒！😊',NULL,NULL,NULL,NULL,'2026-07-18 11:55:01'),(11,1,'float','你好啊','你好呀！😊 我是小智，你的校园服务小帮手～有什么需要帮忙的吗？比如找功能入口、查操作流程，尽管问我！',NULL,NULL,NULL,NULL,'2026-07-18 11:57:01'),(12,1,'float','我想给一卡通充钱','好的！给一卡通充值可以直接在「智慧校园」App里操作，点首页的“一卡通”图标，选“充值”按提示支付就行。或者你也可以去校内自助充值机刷校园卡充值哦～💰 有什么其他问题随时问我呀！',NULL,NULL,NULL,NULL,'2026-07-18 11:57:13');
