DROP TABLE IF EXISTS `ai_knowledge_base`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ai_knowledge_base` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `role_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'ALL' COMMENT '适用角色: ALL/STUDENT/TEACHER/LEADER/ADMIN（逗号分隔）',
  `intent_type` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `question_keywords` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '关键词（用|分隔，用于匹配）',
  `question_patterns` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '常见问法模板（JSON数组）',
  `function_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '对应功能编码（如S-07）',
  `answer_template` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '回答模板（支持变量替换{{var}}）',
  `redirect_url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '快速跳转链接',
  `sort_order` int DEFAULT '0' COMMENT '优先级',
  `status` int DEFAULT NULL,
  `hit_count` int DEFAULT '0' COMMENT '命中次数（用于优化）',
  `created_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  KEY `idx_role` (`role_type`) USING BTREE,
  KEY `idx_intent` (`intent_type`) USING BTREE,
  KEY `idx_function_code` (`function_code`) USING BTREE,
  FULLTEXT KEY `idx_keywords` (`question_keywords`)
) ENGINE=InnoDB AUTO_INCREMENT=20 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci ROW_FORMAT=DYNAMIC COMMENT='AI知识库表';
/*!40101 SET character_set_client = @saved_cs_client */;

