INSERT INTO `ai_knowledge_base` VALUES (1,'STUDENT','FUNCTION_NAV','成绩|分数|挂科|绩点|GPA|查成绩',NULL,'S-07','您可以在「我的成绩」模块查看所有成绩记录。当前{{semester}}学期您的平均绩点为{{gpa}}，共有{{fail_count}}门课程不及格。','/student/score',0,1,0,'2026-07-16 15:53:43','2026-07-16 07:53:43'),(2,'STUDENT','FUNCTION_NAV','课表|课程表|星期|上课|教室',NULL,'S-05','您本周共有{{course_count}}节课，课表详情请点击下方链接查看。','/student/schedule',0,1,0,'2026-07-16 15:53:43','2026-07-16 07:53:43'),(3,'STUDENT','FUNCTION_NAV','选课|选修|退课|选课系统',NULL,'S-14','选课入口在「快捷入口→学生选课」。本学期选课时间为{{start_date}}至{{end_date}}，请按时完成选课。','/student/course-select',0,1,0,'2026-07-16 15:53:43','2026-07-16 07:53:43'),(4,'STUDENT','DATA_QUERY','饭卡|一卡通|消费|余额|食堂',NULL,'S-12','您的一卡通当前余额为¥{{balance}}，最近5笔消费记录已为您列出。','/student/card',0,1,0,'2026-07-16 15:53:43','2026-07-16 07:53:43'),(5,'STUDENT','PROCESS_GUIDE','贫困生|困难生|助学金|助学贷款|申请',NULL,'S-14','申请流程：①进入「快捷入口→学生申请」→②选择「{{application_type}}」→③填写申请信息并上传材料→④提交审核。所需材料：{{material_list}}','/student/application',0,1,0,'2026-07-16 15:53:43','2026-07-16 07:53:43'),(6,'STUDENT','QUERY','查成绩,我的成绩,成绩查询,考试成绩','我(想|要)查.*成绩','S-07','您好，成绩查询功能位于\"课程成绩 → 我的成绩查询\"模块。您可以按学期筛选查看在校期间所有课程成绩，补考/重修会有特殊标识。\n\n👉 [点击前往成绩查询](#)','/student/course/score',1,1,0,'2026-07-17 09:34:54','2026-07-17 01:34:54'),(7,'STUDENT','QUERY','课表,我的课表,课程表,这周有什么课','(我|我的|这周).*课表','S-05','您好，您可以在\"课程管理 → 我的课表\"中查看本学期课程安排，支持周次视图和列表视图两种展示方式。\n\n👉 [点击查看课表](#)','/student/course/schedule',2,1,0,'2026-07-17 09:34:54','2026-07-17 01:34:54'),(8,'STUDENT','QUERY','饭卡,一卡通,校园卡,余额,消费','(我|查|看).*(饭卡|一卡通|校园卡|余额)','S-12','您好，您的一卡通信息可在\"一卡通 → 一卡通信息\"中查看，包括当前余额和最近5笔消费记录。\n\n👉 [点击查看一卡通](#)','/student/card/info',3,1,0,'2026-07-17 09:34:54','2026-07-17 01:34:54'),(9,'STUDENT','QUERY','缴费,学费,欠费','(我|查|看).*(缴费|学费|欠费)','S-13','您好，学费缴费信息可在\"一卡通 → 学费缴费信息\"中查看，包括在校期间所有缴费/欠费明细。\n\n👉 [点击查看缴费](#)','/student/payment/info',4,1,0,'2026-07-17 09:34:54','2026-07-17 01:34:54'),(10,'STUDENT','GUIDE','贫困生,助学金,奖学金,困难,贷款','(怎么|如何).*(申请|办理).*(贫困生|助学金|奖学金|困难|贷款)','S-14','您好，奖学金/助学金/贷款等申请在\"学生服务 → 快捷入口\"中办理。\n\n📋 所需材料：\n1. 填写完整的申请表\n2. 家庭经济情况证明（助学金/贷款需要）\n3. 成绩单（奖学金需要）\n4. 身份证复印件\n\n👉 [点击办理](#)','/student/service/apply',5,1,0,'2026-07-17 09:34:54','2026-07-17 01:34:54'),(11,'STUDENT','QUERY','考试安排,考试时间,考试地点,座位号','(查|看|我).*(考试|考场)','S-08','您好，期末考试安排可在\"考试评教 → 考试安排查询\"中查看，包括考试时间、地点和座位号。\n\n👉 [点击查看考试安排](#)','/student/exam/arrangement',6,1,0,'2026-07-17 09:34:54','2026-07-17 01:34:54'),(12,'STUDENT','NAVIGATION','评教,评价老师','(我|怎么).*评教','S-09','您好，网上评教功能位于\"考试评教 → 网上评教\"模块。您可以对授课教师进行匿名打分评价。当前评教开放时间为2026年6月1日至7月20日。\n\n👉 [点击进入评教](#)','/student/exam/evaluation',7,1,0,'2026-07-17 09:34:54','2026-07-17 01:34:54'),(13,'TEACHER','QUERY','我的课,任课,学生名单','(我|我的|查).*(课|任课|学生名单)','T-04','您好，您可以在\"课程管理 → 任课信息查询\"中查看本周课程安排，点击课程可查看选课学生名单。\n\n👉 [点击查看任课信息](#)','/teacher/course/schedule',1,1,0,'2026-07-17 09:34:54','2026-07-17 01:34:54'),(14,'TEACHER','QUERY','录入成绩,成绩录入','(录入|登记).*成绩','T-05','您好，成绩录入功能位于\"课程管理 → 考试成绩录入\"。请选择课程和学生后录入成绩，支持通过/不及格/缓考/缺考/作弊等标识。\n\n👉 [点击录入成绩](#)','/teacher/course/score',2,1,0,'2026-07-17 09:34:54','2026-07-17 01:34:54'),(15,'LEADER','QUERY','报到率,新生,报到统计','(查|今年|新生).*报到','L-08','您好，新生报到统计位于\"数据统计 → 新生报到统计\"，可查看全校及各学院报到总数、报到率和生源地分布（含ECharts可视化图表）。\n\n👉 [点击查看统计](#)','/leader/statistics/enrollment',1,1,0,'2026-07-17 09:34:54','2026-07-17 01:34:54'),(16,'LEADER','QUERY','缴费率,欠费,注册缴费','(查|缴费率|欠费|注册缴费)','L-09','您好，注册缴费统计位于\"数据统计 → 注册缴费统计\"，可查看全校及各学院注册人数、缴费率和欠费总额。\n\n👉 [点击查看统计](#)','/leader/statistics/payment',2,1,0,'2026-07-17 09:34:54','2026-07-17 01:34:54'),(17,'LEADER','QUERY','在校生,学生数量,学生分布','(查|在校生|学生.*(数量|分布|统计))','L-11','您好，在校生总量统计位于\"数据统计 → 在校生总量统计\"，可按学院/专业/年级查看在校生分布（含ECharts饼图和柱状图）。\n\n👉 [点击查看统计](#)','/leader/statistics/student-count',3,1,0,'2026-07-17 09:34:54','2026-07-17 01:34:54'),(18,'ADMIN','QUERY','登录人数,活跃用户,系统运行','(今天|昨天|有多少).*(登录|活跃)','A-02','您好，系统运行状态可在\"系统管理 → 仪表盘\"中查看，包括今日活跃用户数、待审核注册数、待审批公文数等关键指标。\n\n👉 [点击查看仪表盘](#)','/admin/dashboard',1,1,0,'2026-07-17 09:34:54','2026-07-17 01:34:54'),(19,'ALL','NAVIGATION','帮助,功能,怎么用','(帮助|功能列表|怎么用|有哪些功能)','AI-01','您好！我是智慧校园AI助手，可以帮您：\n\n📌 **快速查询**：成绩、课表、一卡通余额、缴费信息等\n📌 **业务指引**：奖学金申请、考试报名、评教等\n📌 **数据统计**：新生报到率、缴费率、在校生分布等\n\n您可以直接输入问题，我会为您提供精准的答案和快捷入口。',NULL,99,1,0,'2026-07-17 09:34:54','2026-07-17 01:34:54');
