INSERT INTO `announcement` VALUES (1,'关于2025-2026学年第二学期期末考试安排的通知','<p>各学院、各班级：</p><p>根据学校教学工作安排，本学期期末考试将于第18-19周（2026年7月6日-7月17日）进行。请各学院做好考试组织工作，各班级通知学生认真备考。</p><p>具体考试安排请登录系统查看\"考试安排\"模块。</p>',4,'管理员','STUDENT,TEACHER',0,0,'2026-07-01 08:00:00','2026-07-20 23:59:59',359,'PUBLISHED','2026-07-17 09:34:54','2026-07-17 08:04:18'),(2,'关于2026年暑假放假及安全注意事项的通知','<p>全校师生：</p><p>根据校历安排，2026年暑假自7月20日至8月30日，共6周。8月31日（周一）正式上课。</p><p>假期期间请注意人身安全、交通安全和财产安全，祝大家暑假愉快！</p>',4,'管理员','STUDENT,TEACHER,LEADER',1,0,'2026-07-10 09:00:00','2026-09-01 23:59:59',1220,'PUBLISHED','2026-07-17 09:34:54','2026-07-18 04:41:57'),(3,'关于校园一卡通系统升级的公告','<p>各位师生：</p><p>校园一卡通系统将于7月20日-7月25日进行升级维护，期间部分功能可能受限，建议提前充值。升级后支持微信、支付宝扫码支付。</p>',4,'管理员','STUDENT,TEACHER,LEADER,ADMIN',0,1,'2026-07-15 10:00:00','2026-07-26 23:59:59',860,'PUBLISHED','2026-07-17 09:34:54','2026-07-18 03:33:19'),(4,'2026年大学生创新创业训练计划项目申报通知','<p>各学院：</p><p>2026年大学生创新创业训练计划项目申报工作现已启动。本次计划立项国家级项目20项、省级项目50项、校级项目100项。请有意申报的同学于9月15日前提交申请书。</p>',4,'管理员','STUDENT,TEACHER',0,0,'2026-06-20 08:00:00','2026-09-16 23:59:59',575,'PUBLISHED','2026-07-17 09:34:54','2026-07-17 06:03:29'),(5,'关于毕业论文（设计）检测工作的通知','<p>各学院、2027届毕业生：</p><p>根据学校毕业论文管理规定，所有毕业论文（设计）须通过学术不端检测。检测重复率不得超过30%。</p><p>第一批检测时间为2026年12月1日-15日。</p>',4,'管理员','STUDENT,TEACHER',0,0,'2026-06-15 08:00:00','2026-12-16 23:59:59',905,'PUBLISHED','2026-07-17 09:34:54','2026-07-17 06:03:29');
/*!40000 ALTER TABLE `announcement` ENABLE KEYS */;
UNLOCK TABLES;

