DROP TABLE IF EXISTS `card`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `card` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `user_id` bigint NOT NULL COMMENT '持卡人ID',
  `card_no` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '一卡通卡号',
  `balance` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '当前余额',
  `card_status` varchar(10) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `issue_date` date DEFAULT NULL COMMENT '发卡日期',
  `expire_date` date DEFAULT NULL COMMENT '有效期至',
  `daily_limit` decimal(10,2) DEFAULT '200.00' COMMENT '日消费限额',
  `created_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_card_no` (`card_no`) USING BTREE,
  KEY `idx_user` (`user_id`) USING BTREE,
  KEY `idx_card_status` (`card_status`) USING BTREE,
  CONSTRAINT `fk_card_user` FOREIGN KEY (`user_id`) REFERENCES `user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE=InnoDB AUTO_INCREMENT=38 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='一卡通主表';
/*!40101 SET character_set_client = @saved_cs_client */;

