INSERT INTO `course` VALUES (1,'CS101','数据结构与算法','Data Structures and Algorithms',4.0,64,4,'REQUIRED','计算机学院','本课程介绍基本的数据结构（线性表、栈、队列、树、图）和经典算法（排序、搜索、动态规划等）。',1,'2026-07-17 09:34:54','2026-07-17 01:34:54'),(2,'CS102','操作系统原理','Operating Systems',3.5,56,4,'REQUIRED','计算机学院','学习操作系统的基本原理，包括进程管理、内存管理、文件系统和I/O管理。',1,'2026-07-17 09:34:54','2026-07-17 01:34:54'),(3,'CS103','数据库原理与应用','Database Principles',3.0,48,3,'REQUIRED','计算机学院','介绍关系数据库的基本概念、SQL语言、数据库设计和规范化理论。',1,'2026-07-17 09:34:54','2026-07-17 01:34:54'),(4,'CS201','人工智能导论','Introduction to AI',3.0,48,3,'REQUIRED','计算机学院','涵盖搜索、知识表示、机器学习、深度学习等AI核心领域的基础知识。',1,'2026-07-17 09:34:54','2026-07-17 01:34:54'),(5,'CS202','软件工程','Software Engineering',3.0,48,3,'REQUIRED','计算机学院','学习软件开发全生命周期管理，包括需求分析、系统设计、编码、测试和维护。',1,'2026-07-17 09:34:54','2026-07-17 01:34:54'),(6,'CS301','计算机网络','Computer Networks',3.5,56,4,'REQUIRED','计算机学院','学习计算机网络体系结构、各层协议、网络安全等。',1,'2026-07-17 09:34:54','2026-07-17 01:34:54'),(7,'MATH201','高等数学（下）','Advanced Mathematics II',5.0,80,5,'REQUIRED','理学院','多元函数微积分、级数、常微分方程等。',1,'2026-07-17 09:34:54','2026-07-17 01:34:54'),(8,'MATH202','线性代数','Linear Algebra',3.0,48,3,'REQUIRED','理学院','矩阵理论、线性空间、线性变换、特征值与特征向量。',1,'2026-07-17 09:34:54','2026-07-17 01:34:54'),(9,'BUS101','管理学原理','Principles of Management',3.0,48,3,'REQUIRED','经管学院','管理的基本概念、计划、组织、领导和控制职能。',1,'2026-07-17 09:34:54','2026-07-17 01:34:54'),(10,'BUS102','会计学基础','Fundamentals of Accounting',3.0,48,3,'REQUIRED','经管学院','会计基本理论、复式记账、财务报表编制与分析。',1,'2026-07-17 09:34:54','2026-07-17 01:34:54');
