LOCK TABLES `news` WRITE;
/*!40000 ALTER TABLE `news` DISABLE KEYS */;
INSERT INTO `news` VALUES (1,'我校在2026年全国大学生计算机设计大赛中获佳绩','我校代表队荣获全国一等奖2项、二等奖3项、三等奖5项，创历史最好成绩。','<p>近日，2026年（第19届）全国大学生计算机设计大赛总决赛在厦门大学举行。我校计算机学院选派8支队伍参赛，经过激烈角逐，最终获得全国一等奖2项、二等奖3项、三等奖5项。</p><p>本次大赛共有来自全国500余所高校的3000余支队伍参赛。我校参赛作品涵盖人工智能应用、软件应用与开发、物联网应用等多个类别。</p>','news1.jpg','学校要闻','计算机学院',4,'管理员',2064,189,'PUBLISHED','2026-07-10 14:30:00','2026-07-17 09:34:54','2026-07-18 07:09:07'),(2,'我校与华为技术有限公司签署战略合作协议','双方将在人才培养、科研合作、智慧校园建设等方面开展深度合作。','<p>7月5日上午，我校与华为技术有限公司战略合作签约仪式在学术报告厅举行。华为公司副总裁张某某、校党委书记李某某出席签约仪式。</p><p>根据协议，华为将在学校设立\"华为创新人才奖学金\"，每年投入500万元用于资助优秀学子。双方还将在AI大模型、云计算、物联网等领域开展联合科研攻关。</p>','news2.jpg','学校要闻','校办',4,'管理员',3145,256,'PUBLISHED','2026-07-05 10:00:00','2026-07-17 09:34:54','2026-07-18 07:09:10'),(3,'2026年校园招聘会圆满落幕 提供岗位12000+','本次招聘会共有300余家企业参会，提供就业岗位12000余个，5000余名毕业生到场求职。','<p>6月20日，我校2026年夏季校园招聘会在体育馆举行。参加本次招聘会的企业包括阿里巴巴、腾讯、字节跳动、国家电网、中建集团等知名企业。</p><p>据统计，招聘会现场达成初步就业意向3200余人次，创历年新高。</p>','news3.jpg','就业创业','招生就业处',4,'管理员',4521,312,'PUBLISHED','2026-06-22 16:00:00','2026-07-17 09:34:54','2026-07-18 04:34:44'),(4,'图书馆新增数字化学习资源平台','学校图书馆引进了知网、万方、IEEE、ACM等40余个数据库资源。','<p>为更好服务师生教学科研需求，学校图书馆本学期新增了多个数字化学习资源平台。</p><p>目前已开通试用的新平台包括：ChatGPT学术版、AI论文写作助手、虚拟仿真实验平台等。师生可通过校园网免费访问。</p>','news4.jpg','校园生活','图书馆',4,'管理员',1521,98,'PUBLISHED','2026-06-15 09:00:00','2026-07-17 09:34:54','2026-07-18 07:09:13');
/*!40000 ALTER TABLE `news` ENABLE KEYS */;
UNLOCK TABLES;

