INSERT INTO `student_application` VALUES (1,1,'SCHOLARSHIP','2025-2026学年国家励志奖学金申请','本人学习成绩优异，学年平均绩点3.8，获校级三好学生、优秀学生干部等荣誉称号。家庭经济困难，符合国家励志奖学金申请条件。',NULL,'2025-2026-2','APPROVED','材料齐全，条件符合，同意推荐。','2026-04-15 10:00:00','2026-05-10 14:00:00',2,'2026-07-17 09:34:54','2026-07-17 03:32:59'),(2,7,'SUBSIDY','家庭经济困难学生认定申请','本人来自农村低保家庭，父母务农，年收入不足2万元。本人申请认定为家庭经济困难学生，以便获取国家和学校的资助。',NULL,'2025-2026-2','PENDING',NULL,'2026-06-20 16:00:00',NULL,NULL,'2026-07-17 09:34:54','2026-07-17 01:34:54'),(3,8,'LOAN','生源地信用助学贷款申请','因家庭经济原因，本人申请生源地信用助学贷款8000元/年，用于缴纳学费和住宿费。',NULL,'2025-2026-2','APPROVED','家庭经济情况属实，同意申请。','2026-06-01 09:00:00','2026-06-15 10:00:00',2,'2026-07-17 09:34:54','2026-07-17 03:32:59'),(4,11,'SCHOLARSHIP','校级优秀学生奖学金申请','本人上学期平均分92分，班级排名第1，积极参加学科竞赛和社会实践活动，申请校级优秀学生奖学金。',NULL,'2025-2026-2','PENDING',NULL,'2026-07-05 08:00:00',NULL,NULL,'2026-07-17 09:34:54','2026-07-17 01:34:54'),(5,1,'贷款','助学贷款','111',NULL,'2025-2026-2',NULL,'同意','2026-07-17 11:28:51','2026-07-17 13:00:00',0,'2026-07-17 11:28:51','2026-07-17 05:00:00'),(6,1,'贷款','1','1',NULL,'2025-2026-2',NULL,'','2026-07-17 13:19:38','2026-07-17 13:19:51',0,'2026-07-17 13:19:38','2026-07-17 05:19:51'),(7,1,'助学金','1','1',NULL,'2025-2026-2','APPROVED','辅导员审核通过，提交院长审批; 院长:院长审批通过','2026-07-17 13:25:46','2026-07-17 13:26:38',2,'2026-07-17 13:25:46','2026-07-17 05:26:38'),(8,1,'贷款','4','4',NULL,'2025-2026-2','APPROVED','辅导员审核通过，提交院长审批; 院长:院长审批通过','2026-07-17 16:24:19','2026-07-17 16:25:16',2,'2026-07-17 16:24:19','2026-07-17 08:25:16');
